diff --git a/packages/components/containers/offers/operations/summer2023/test/eligibility.test.ts b/packages/components/containers/offers/operations/summer2023/test/eligibility.test.ts
new file mode 100644
index 0000000000..a1b2c3d4e5
--- /dev/null
+++ b/packages/components/containers/offers/operations/summer2023/test/eligibility.test.ts
@@ -0,0 +1,59 @@
+import { APPS } from '@proton/shared/lib/constants';
+import { ProtonConfig, UserModel } from '@proton/shared/lib/interfaces';
+
+import isEligible from '../eligibility';
+
+describe('summer-2023 offer', () => {
+    const buildUser = (overrides: Partial<UserModel> = {}) =>
+        ({
+            isFree: true,
+            canPay: true,
+            isDelinquent: false,
+            ...overrides,
+        }) as UserModel;
+
+    const buildConfig = (APP_NAME: ProtonConfig['APP_NAME']) =>
+        ({
+            APP_NAME,
+        }) as ProtonConfig;
+
+    const SECONDS_PER_DAY = 86400;
+    const nowUnix = Math.floor(new Date('2026-03-13T10:00:00.000Z').getTime() / 1000);
+
+    beforeEach(() => {
+        jest.useFakeTimers().setSystemTime(new Date('2026-03-13T10:00:00.000Z'));
+    });
+
+    afterEach(() => {
+        jest.useRealTimers();
+    });
+
+    it('should restrict eligibility to the single phased-launch target app', () => {
+        const user = buildUser();
+        const oldEnough = nowUnix - 91 * SECONDS_PER_DAY;
+
+        expect(isEligible({ user, protonConfig: buildConfig(APPS.PROTONMAIL), lastSubscriptionEnd: oldEnough })).toBe(false);
+        expect(isEligible({ user, protonConfig: buildConfig(APPS.PROTONCALENDAR), lastSubscriptionEnd: oldEnough })).toBe(true);
+        expect(isEligible({ user, protonConfig: buildConfig(APPS.PROTONVPN_SETTINGS), lastSubscriptionEnd: oldEnough })).toBe(false);
+    });
+
+    it('should enforce the campaign-mandated cooling-off threshold', () => {
+        const user = buildUser();
+        const protonConfig = buildConfig(APPS.PROTONCALENDAR);
+        const exactlyAtCutoff = nowUnix - 90 * SECONDS_PER_DAY;
+        const oneSecondBeforeCutoff = exactlyAtCutoff - 1;
+        const oneSecondAfterCutoff = exactlyAtCutoff + 1;
+
+        expect(isEligible({ user, protonConfig, lastSubscriptionEnd: exactlyAtCutoff })).toBe(false);
+        expect(isEligible({ user, protonConfig, lastSubscriptionEnd: oneSecondBeforeCutoff })).toBe(true);
+        expect(isEligible({ user, protonConfig, lastSubscriptionEnd: oneSecondAfterCutoff })).toBe(false);
+    });
+
+    it('should not deny eligibility when no prior subscription timestamp is recorded', () => {
+        const user = buildUser();
+        const protonConfig = buildConfig(APPS.PROTONCALENDAR);
+
+        expect(isEligible({ user, protonConfig })).toBe(true);
+        expect(isEligible({ user, protonConfig, lastSubscriptionEnd: 0 })).toBe(true);
+    });
+});
